#define GM_ADDR __gm__ uint8_t*  // To avoid #include "kernel_operator.h"
#endif

#define CONST_HALF_TO_GM(x) \
  reinterpret_cast<__gm__ half*>(const_cast<__gm__ half*>((x)))

